Here's a basic example of how to save an image to localStorage:

javascript
function saveImageToLocalStorage(imageDataUrl, imageName) {
  // Get existing images from localStorage or initialize empty array
  const savedImages = JSON.parse(localStorage.getItem('rpgPortraits')) || [];

  // Create image object to store
  const imageObj = {
    id: Date.now(), // Unique identifier
    name: imageName,
    dataUrl: imageDataUrl,
    createdAt: new Date().toISOString()
  };

  // Add new image to the array
  savedImages.push(imageObj);

  // Save back to localStorage
  localStorage.setItem('rpgPortraits', JSON.stringify(savedImages));
}

// Example usage:
const profilePic = 'data:image/png;base64,iVBORw0KGgoAAAANSUhEUg...';
saveImageToLocalStorage(profilePic, 'Elven Archer');
